write_if_needed "${playground_dir}/tables/example_timing_summary.tex" <<'EOF'
\begin{table}[tbp]
  \centering
  \caption{Representative timing-performance summary for three reconstruction
  configurations. The quoted uncertainty is the run-to-run spread of the fitted
  timing resolution.}
  \label{tab:example-timing}
  \begin{tabular}{l S[table-format=2.0] S[table-format=1.3(2)] S[table-format=1.3]}
    \toprule
    Configuration & {Threshold [\si{\milli\volt}]} & {Resolution [\si{\nano\second}]} & {Efficiency} \\
    \midrule
    Leading-edge discriminator & 20 & 0.245(12) & 0.934 \\
