write_if_needed "${playground_dir}/scripts/generate_example_figure.py" <<'EOF'
from pathlib import Path

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd
from scipy.optimize import curve_fit


ROOT = Path(__file__).resolve().parents[1]
DATA_PATH = ROOT / "data" / "example_energy_resolution.csv"
OUTPUT_PATH = ROOT / "figures" / "generated" / "example_energy_resolution.pdf"


def resolution_model(energy_mev: np.ndarray, stochastic: float, constant: float) -> np.ndarray:
    return np.sqrt((stochastic / np.sqrt(energy_mev)) ** 2 + constant**2)


def main() -> None:
    data = pd.read_csv(DATA_PATH)

    fit_parameters, _ = curve_fit(
        resolution_model,
        data["energy_mev"],
        data["resolution_pct"],
        sigma=data["resolution_err_pct"],
        absolute_sigma=True,
        p0=(95.0, 2.5),
    )

    energy_grid = np.linspace(data["energy_mev"].min(), data["energy_mev"].max(), 500)
    fit_curve = resolution_model(energy_grid, *fit_parameters)

    plt.rcParams.update(
        {
            "font.family": "serif",
            "font.size": 12,
            "axes.labelsize": 12,
            "axes.titlesize": 12,
            "legend.fontsize": 10,
            "xtick.labelsize": 11,
            "ytick.labelsize": 11,
            "pdf.fonttype": 42,
            "ps.fonttype": 42,
        }
    )

    figure, axis = plt.subplots(figsize=(6.4, 4.4), constrained_layout=True)

    axis.errorbar(
        data["energy_mev"],
        data["resolution_pct"],
        yerr=data["resolution_err_pct"],
        fmt="o",
        color="#1f4e79",
        markerfacecolor="#1f4e79",
        markeredgecolor="white",
        markeredgewidth=0.8,
        capsize=3,
        linewidth=1.2,
        label="Measured points",
    )
    axis.plot(
        energy_grid,
        fit_curve,
        color="#b44b20",
        linewidth=2.0,
        label="Fit to resolution model",
    )

    axis.set_xlabel("Beam energy [MeV]")
    axis.set_ylabel("Energy resolution [%]")
    axis.set_xlim(35, 415)
    axis.set_ylim(4.0, 15.5)
    axis.grid(True, which="major", color="#d9d9d9", linewidth=0.7)
    axis.spines["top"].set_visible(False)
    axis.spines["right"].set_visible(False)

    stochastic, constant = fit_parameters
    axis.text(
        0.04,
        0.95,
        (
            r"$R(E)=\sqrt{(a/\sqrt{E})^2+b^2}$" "\n"
            rf"$a={stochastic:.1f}$, $b={constant:.2f}$"
        ),
        transform=axis.transAxes,
        va="top",
        ha="left",
        bbox={"boxstyle": "round,pad=0.3", "facecolor": "white", "edgecolor": "#c0c0c0"},
    )
    axis.legend(frameon=False, loc="upper right")

    OUTPUT_PATH.parent.mkdir(parents=True, exist_ok=True)
    figure.savefig(OUTPUT_PATH, bbox_inches="tight")


if __name__ == "__main__":
    main()
EOF

chmod +x "${playground_dir}/scripts/generate_example_figure.py"

echo "Playground ready at: ${playground_dir}"
if [[ "${overwrite}" -eq 0 ]]; then
  echo "Existing playground files were left untouched."
else
  echo "Playground files were refreshed."
fi
